// T049: Enqueue action into Workflow Static Data queue
// Adds entries from the verified webhook request body to the action queue

const body = $input.all()[0].json.body;
const staticData = $getWorkflowStaticData('global');

if (!staticData.queue) {
  staticData.queue = [];
}

const entry = {
  id: `action_${Date.now()}_${Math.random().toString(36).substr(2, 6)}`,
  action_type: body.action_type,
  target_urn: body.target_urn,
  text: body.text || null,
  scheduled_at: body.scheduled_at || new Date().toISOString(),
  status: 'pending'
};

staticData.queue.push(entry);

return [{
  json: {
    status: 'queued',
    entry: entry,
    queue_length: staticData.queue.length
  }
}];

// T049: Read queue from Static Data, filter for items that are due

const staticData = $getWorkflowStaticData('global');

if (!staticData.queue) {
  staticData.queue = [];
}

const now = new Date();
const dueItems = staticData.queue.filter(item => {
  if (item.status !== 'pending') return false;
  const scheduledAt = new Date(item.scheduled_at);
  return scheduledAt <= now;
});

if (dueItems.length === 0) {
  return [{ json: { status: 'idle', message: 'No due items in queue', queue_length: staticData.queue.length } }];
}

// Return due items for processing
return dueItems.map(item => ({ json: item }));

// T049: Execute due action by calling the appropriate workflow webhook
// and update the queue entry status in Static Data

const item = $input.all()[0].json;

// Skip if this is an idle status message (no due items)
if (item.status === 'idle') {
  return [{ json: item }];
}

const staticData = $getWorkflowStaticData('global');

let endpoint = '';
let payload = {};

switch (item.action_type) {
  case 'like':
    endpoint = 'http://localhost:5678/webhook/linkedin-like';
    payload = { action: 'like', target_urn: item.target_urn };
    break;
  case 'comment':
    endpoint = 'http://localhost:5678/webhook/linkedin-comment';
    payload = { action: 'comment', draft_id: item.id, target_urn: item.target_urn, text: item.text };
    break;
  default:
    // Mark as failed for unknown action types
    const idx = staticData.queue.findIndex(q => q.id === item.id);
    if (idx >= 0) {
      staticData.queue[idx].status = 'failed';
      staticData.queue[idx].error = `Unknown action_type: ${item.action_type}`;
    }
    return [{ json: { status: 'failed', id: item.id, error: `Unknown action_type: ${item.action_type}` } }];
}

// Mark as executed in the queue
const queueIdx = staticData.queue.findIndex(q => q.id === item.id);
if (queueIdx >= 0) {
  staticData.queue[queueIdx].status = 'executed';
  staticData.queue[queueIdx].executed_at = new Date().toISOString();
}

// Prune completed items older than 24 hours
const oneDayAgo = new Date(Date.now() - 86400000).toISOString();
staticData.queue = staticData.queue.filter(q =>
  q.status === 'pending' || (q.executed_at && q.executed_at > oneDayAgo)
);

return [{
  json: {
    status: 'executed',
    id: item.id,
    action_type: item.action_type,
    target_urn: item.target_urn,
    endpoint: endpoint
  }
}];
